INSERT INTO catalog_groups VALUES(183,'OGT No.156 국보','2025. 11. 21. 발행 | 1종',33,2,1,'#F5121B','movie','https://i.namu.wiki/i/md1DYYV8Iv5MarGxqGAR5FvdnbyvNguB-_UaTY6StRoJ08UEfH24qiq5CAVzS2F8zoRIAgYl7F83E6sFmKVV_fJDhsTjIs2pYqwH_1eytxngt1al0WPqKp5T8ckyQx2vKsd4SV3O7aN7TeuP3OmV1w.webp',1,'published',0,1,'2026-02-27 19:17:14','2026-02-27 19:17:14');
INSERT INTO catalog_groups VALUES(184,'약한영웅','연시은은 공부 외엔 관심이 없지만 걸어온 싸움을 피하지도 않는다. 타고난 두뇌로 유리한 상황을 만들고 주변 도구를 활용하여 자신을 보호하던 시은이지만 혼자이기에 결국 위기가 닥치고, 그 순간 또 다른 아웃사이더 안수호와 전학생 오범석의 도움을 받는다. 그렇게 정글 같은 학교에서 살아남기 위해 따로 또 같이 싸우던 이들 사이에 묘한 우정이 싹튼다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/oLwotnApTObF5bMRrNHCaqpaZce.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:41:00');
INSERT INTO catalog_groups VALUES(185,'이 사랑 통역 되나요?','촬영차 전 세계를 오가는 스타 배우와 그녀의 통역사. 서로를 향한 마음이 깊어지는 것과 달리 설렘의 감정은 자꾸만 오역이 되는데. 과연 둘만의 사랑의 언어를 찾을 수 있을까?',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/zL3BlyLxr5rrbZYITeOBAW2K5xv.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:41:11');
INSERT INTO catalog_groups VALUES(186,'흑백요리사: 요리 계급 전쟁','경력과 장르를 가리지 않는다. 그저 요리만 잘하면 된다. 레스토랑 셰프부터 방구석 요리왕까지, 맛에 일가견이 있는 사람들의 경쟁. 그 어디에서도 볼 수 없던 치열한 요리 대결이 시작된다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/p63GY5JaHX4fine4fgQkhSoqc6r.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:41:20');
INSERT INTO catalog_groups VALUES(187,'폭싹 속았수다','당차고 야무진 소녀와 우직하고 헌신적인 소년. 제주 바닷가 작은 마을에서 한 뼘씩 자라온 두 사람의 인생은 어디로 향할까. 넘어지고 좌절해도 다시 일어서며, 세월을 뛰어넘어 피어나는 사랑 이야기.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/mwczMJeoQrsPERcyP1e900jo3Jv.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:41:32');
INSERT INTO catalog_groups VALUES(188,'다 이루어질지니','천여 년 만에 컴백한 경력 단절 정령 지니, 감정이 결여된 인간 가영을 만나다. 늘 할머니의 룰과 자신의 루틴대로만 살던 그녀 앞에 놓인 세 가지 소원, 그리고 시작되는 예측 불가 판타지 로맨스.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/2ds9EWX7cwGfZiRjYqhyw7SbzsW.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:41:44');
INSERT INTO catalog_groups VALUES(189,'중증외상센터','전장에서 경험을 쌓은 외과 전문의가 한국에 돌아온다. 뛰어난 실력으로 거침없이 돌진하는 그의 목표는 최고의 중증외상센터 건설. 그의 팀원들도 생명을 구하는 인재들로 성장해 간다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/58XBnfKhP569SuZuXks3fNYpLBm.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:41:54');
INSERT INTO catalog_groups VALUES(190,'전,란','조선 최고 무신 집안의 아들 종려와 그의 몸종 천영. 함께 자란 두 남자가 왜란의 시대에 적이 되어 다시 만난다. 한 사람은 선조의 최측근 무관으로, 다른 사람은 의병으로, 파란의 세월을 헤쳐간다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/qcHOh5PoygMtPbhpeBC0VUNNtAp.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:42:04');
INSERT INTO catalog_groups VALUES(191,'더 글로리','고등학교 시절, 끔찍한 괴롭힘에 시달렸던 여자. 많은 시간이 흐른 후, 가해자들을 응징하기 위해 그녀가 치밀한 복수를 감행한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/AjwoDj77HLlqcpwEGqsnvMXm5my.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:42:21');
INSERT INTO catalog_groups VALUES(192,'자백의 대가','남편을 죽였다는 혐의로 궁지에 몰린 여자. 그녀에게 의문의 여인이 다가와 거래를 제안한다. 그 사건을 대신 자백해 주겠다는 약속. 하지만 그 대가로 누군가의 목숨을 가져와야만 한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/kgqzwaOzgkaAj12XLYxgK5wB7XA.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:42:29');
INSERT INTO catalog_groups VALUES(193,'정신병동에도 아침이 와요','정신건강의학과에 새로 오게 된 간호사 정다은. 아무리 힘든 일이 생겨도 환자들에게 따뜻한 아침 햇살 같은 존재가 되기 위해 최선을 다한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/bhCUn6Z509qTV4eBJZtjtQ4ennL.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:42:37');
INSERT INTO catalog_groups VALUES(194,'지금 우리 학교는','좀비 바이러스 발생의 시발점이 된 고등학교. 이곳에 갇힌 학생들은 필사적으로 탈출구를 찾아야만 한다. 그렇지 않으면 감염되어 좀비가 될 뿐.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/8hp2CuGnw1iP5dLBVMAPUv23swx.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:42:45');
INSERT INTO catalog_groups VALUES(195,'은중과 상연','10대부터 함께한 은중과 상연. 동경과 질투, 애증이 20대, 30대를 채우다 결국 돌이킬 수 없이 멀어졌다. 이제 마흔셋. 은중은 상연의 마지막 여정에 동행해 달라는 부탁을 받는다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/5Ia4bJ0GuAn84H98CCtWMRVCTAF.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:42:53');
INSERT INTO catalog_groups VALUES(196,'셀러브리티','인기가 돈이자 권력이 되는 곳. 서울의 화려하고도 치열한 인플루언서의 세계에 뛰어든 서아리의 목표는 누구보다 핫한 셀럽이 되는 거다. 유명해지기만 하면 돈이 되는 세계에 뛰어든 아리가 마주한 셀럽들의 화려하고도 치열한 민낯을 그린 넷플릭스 오리지널 시리즈.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/ggOukDTllje9G36qKuXJtzMcRRT.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:43:02');
INSERT INTO catalog_groups VALUES(197,'사마귀','하룻밤 사이 몰락한 청부살인 업계의 거물들. 그들이 세운 질서가 무너지고, 어둠의 세계가 흔들린다. 혼돈 속에서 기회를 노리는 실력자 ''사마귀''. 그의 손끝에서 새로운 킬러들의 시대가 열린다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/yOFqBpJ0PEkBdQqalDEaeOiaKbz.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:43:12');
INSERT INTO catalog_groups VALUES(198,'광장','스스로 아킬레스건을 자르고 광장을 떠났던 기준. 그가 조직의 2인자였던 동생 기석의 죽음을 파헤치고자 11년 만에 돌아온다. 차가운 복수를 향해 타협 없이 직진하는 강렬한 누아르 액션.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/fWJjsS2Tr2dlpYuw3o7Lifvgkru.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:43:26');
INSERT INTO catalog_groups VALUES(199,'불량 연애','사회의 주변인으로 살아가는 11인의 남녀. 14일간 공동생활을 하면서, 서로 충돌하기도 하고 유대를 다지기도 하며 진짜 사랑을 찾는다. 일본 최초의 불량배 순애 리얼리티 쇼.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/vmQhEYL4VP7jjaNC5qNSETGHGJc.jpg',1,'published',2,1,'2026-02-28 08:45:15','2026-03-02 08:43:37');
INSERT INTO catalog_groups VALUES(200,'오징어 게임','빚에 쫓기는 수백 명의 사람들이 서바이벌 게임에 뛰어든다. 거액의 상금으로 새로운 삶을 시작하기 위해. 하지만 모두 승자가 될 순 없는 법. 탈락하는 이들은 치명적인 결과를 각오해야 한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/2meX1nMdScFOoV4370rqHWKmXhY.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:43:48');
INSERT INTO catalog_groups VALUES(201,'대홍수','대홍수가 덮친 지구 종말의 날. 물에 잠겨가는 아파트에 갇힌 연구원과 어린 아들이 탈출을 시도한다. 그 순간 도착한 중대 임무. 그녀는 인류의 운명이 걸린 과제를 끝까지 완수할 수 있을까.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/8vLt9TYFZdAwYtqImvggTM5yFnF.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:43:56');
INSERT INTO catalog_groups VALUES(202,'당신이 죽였다','나는 친구의 남편을 죽이기로 결심했다. 지옥 같은 현실에서 탈출하고자 살인을 계획한 두 여자. 하지만 위험한 도박을 시작한 그녀들에게 예상치 못한 방문객이 찾아오고 모든 것이 무너질 위기에 처한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/7uVNWsjnmkvqpeqWHq5qpLBv3wd.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:44:06');
INSERT INTO catalog_groups VALUES(203,'향기로운 꽃은 늠름하게 핀다','위협적인 외모 때문에 오해를 받는 린타로와 그런 린타로를 스스럼없이 대하는 카오루코. 우연히 알게 된 두 사람은 서로 가까워지지만, 이웃해 있는 둘의 고등학교는 서로를 철저히 혐오한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/dl3pdT1NZiqRM4aDBwsD2TtO8x9.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:44:17');
INSERT INTO catalog_groups VALUES(204,'수리남','2022년 9월 Netflix에서 방영을 시작한 범죄물. 남미에서 마약 조직을 운영하는 한국인 마약왕. 그를 체포하려는 정부의 비밀 작전에 한 평범한 사업가가 합류한다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/haIqIHTTZPebqPTz3ktte1VEUDL.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:44:31');
INSERT INTO catalog_groups VALUES(205,'캐셔로','초능력을 얻게 된 평범한 남자. 그러나 초능력을 사용할 때마다 지갑 속 돈이 줄어드는 탓에 마음 편히 싸울 수가 없다. 설상가상 초능력을 훔치려는 나쁜 놈마저 기승을 부리고 있으니.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/lr0h0OBj7QOEvkaX5g3JWoaKZsI.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:44:44');
INSERT INTO catalog_groups VALUES(206,'파반느','백화점에서 일하는 세 사람. 서로에게 그저 낯선 타인이었던 외로운 이들. 점차 서로에게 빛이 되어주며 삶의 의미와 사랑의 본질을 알아나간다.',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/atWzbjlDkfbkh4mdY3uuiF9vr3r.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:44:52');
INSERT INTO catalog_groups VALUES(207,'트리거','정의감 가득한 트리거 팀장과 지독한 개인주의자인 PD를 중심으로 탐사보도 제작진이 미스터리한 사건들의 진실을 밝히고 폐지 위기의 프로그램을 지켜내는 이야기',39,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/eIcCM6RuwVRhojyCLca9lmAs37L.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:45:03');
INSERT INTO catalog_groups VALUES(208,'케냐 간 세끼','대도시 나이로비에서 대자연 마사이마라까지, 케냐를 무대로 엉뚱발랄 3인방의 모험이 펼쳐진다. 느긋한 힐링 따위 잊어야 하는 여행. 온갖 게임이 숨돌릴 틈도 없이 이어진다.',41,2,1,'#E50914','star','https://image.tmdb.org/t/p/original/hisigWf5HWftTSFXyvS8o50Geuc.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:45:12');
INSERT INTO catalog_groups VALUES(209,'크라임씬 제로','용의자와 탐정이 된 플레이어가 그들 가운데 숨어있는 범인을 찾아내는 국내 최초로 시도된 레전드 롤플레잉 추리 게임',41,2,1,'#E50914','star','https://image.tmdb.org/t/p/original/i0kPV83Py7q0mGWiDBPLdzljeQX.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:45:22');
INSERT INTO catalog_groups VALUES(210,'솔로지옥','매력적인 싱글 남녀가 무인도에 갇혔다. 누군가와 커플이 되는 게 유일한 탈출 방법. 근데 커플들이 ''천국도''로 이동해 밤을 불태울 때, 솔로는 ''지옥도''에 남아 자급자족해야 한다고?',41,2,1,'#E50914','star','https://image.tmdb.org/t/p/original/bkz7rStamWJxC3lp9TUpU9GR18S.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:45:31');
INSERT INTO catalog_groups VALUES(211,'피지컬: 아시아','8개국을 대표하는 피지컬 최강자들이 국가의 명예를 걸고 대결한다. 극한의 체력과 인내심의 한계를 건 치열한 전투 끝에 단 하나의 국기만이 남게 된다.',41,2,1,'#E50914','star','https://image.tmdb.org/t/p/original/823qOjKt0V0N9S6h2uoqu1IA15f.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:45:40');
INSERT INTO catalog_groups VALUES(212,'레이디 두아','가짜일지라도 명품이 되고 싶었던 여자 사라킴. 어디서나 그녀의 이름을 들을 수 있지만 어디서도 진짜 그녀를 만날 수는 없다. 예리한 시선과 끈질긴 집념의 형사 무경이 그 미스터리한 정체를 추적한다.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/4YWpfFrtd6PBAQmkI44DEkCP13O.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:45:47');
INSERT INTO catalog_groups VALUES(213,'나이트 에이전트','한밤중의 전화로 엮인 FBI 요원과 사이버보안 전문가. 점점 더 커져가는 정치적 음모를 함께 파헤쳐야만 한다.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/gklrevVndG98GHGDwfm8y8kxESo.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:45:56');
INSERT INTO catalog_groups VALUES(214,'매니페스트','몬테고 비행기 828기가 사라지고 5년이 지난 어느 날 비행기가 다시 나타난다. 승객들은 모두 무사했지만 자신들이 알지 못하는 사이 5년이란 시간이 흘러버렸음을 알게 되고, 모든 것들이 변해버린 상황에 닥친 이야기',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/iZu83GB1IM7VXL2X90m7iLHYUHU.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:46:04');
INSERT INTO catalog_groups VALUES(215,'피키 블라인더스','1919년 영국 버밍엄. 토마스 셸비를 주축으로 한 셸비 가문은 악명 높은 범죄 조직 "피키 블라인더스"를 이끌고 암흑가의 정상을 차지하기 위해 수단과 방법을 가리지 않는다.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/l8v3gJDlASN0lNn51gR8zQJsu5O.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:46:13');
INSERT INTO catalog_groups VALUES(216,'링컨 차를 타는 변호사','로스앤젤레스의 잘나가는 변호사 미키 홀러. 자신의 분신 같은 링컨 차에서 형사 사법제도에 대처하며 사건을 해결해 나간다. 이길 수만 있다면 수단과 방법을 가리지 않고.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/jBFOVEE5sMIyT141YIqIwyU8Y1D.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:46:22');
INSERT INTO catalog_groups VALUES(217,'기묘한 이야기','인디애나주의 작은 마을에서 행방불명된 소년. 이와 함께 미스터리한 힘을 가진 소녀가 나타나고, 마을에는 기묘한 현상들이 일어나기 시작한다. 아들을 찾으려는 엄마와 마을 사람들은 이제 정부의 일급비밀 실험의 실체와 무시무시한 기묘한 현상들에 맞서야 한다.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/8zbAoryWbtH0DKdev8abFAjdufy.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:46:32');
INSERT INTO catalog_groups VALUES(218,'브리저튼','진실한 애정과 끈끈한 유대로 맺어진 브리저튼 가문의 8남매. 그들이 런던의 상류사회에서 사랑과 행복을 향한 여정을 떠난다.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/5NEegdKUJW0TtGt1Wi3Z5nL4SSd.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:46:44');
INSERT INTO catalog_groups VALUES(219,'웬즈데이','똑똑함은 기본, 비꼬는 것에도 도가 튼 웬즈데이 아담스. 암울함을 풍기는 그녀가 네버모어 아카데미에서 얽히고설킨 미스터리를 파헤치기 시작한다. 새 친구도 사귀고, 앙숙도 만들며.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/iHSwvRVsRyxpX7FE7GbviaDvgGZ.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:46:53');
INSERT INTO catalog_groups VALUES(220,'루시퍼','지긋지긋한 지옥 생활을 청산하고 은퇴를 선언한 악마. LA로 와 나이트클럽을 열고 인생을 즐기던 어느 날 강력계 형사를 만나면서 새로운 삶을 살기 시작한다.',40,2,1,'#E50914','tv','https://image.tmdb.org/t/p/original/ncftkNAjIz2PBbUMY7T0CHVJP8d.jpg',1,'published',0,1,'2026-02-28 08:45:15','2026-03-02 08:47:01');
INSERT INTO catalog_groups VALUES(221,'바키도','일본 사상 최강의 검사 미야모토 무사시. 그의 부활과 함께, 바키와 지하격투장의 강력한 격투가들은 시간을 초월해 등장한 위협과 직면한다.',42,2,1,'#FF9800','star','https://image.tmdb.org/t/p/original/1M8uW8o6fdDaa3zqmBD2UUKu0VZ.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:47:21');
INSERT INTO catalog_groups VALUES(222,'던전밥','던전밥. ''먹을 것''이냐, 아니면 ''먹힐 것''이냐... 던전 깊은 곳, 레드 드래곤에게 먹힌 여동생을 두고 간신히 지상으로 생환한 모험가 라이오스. 다시 던전으로 들어가려 하지만, 돈도 식량도 모두 미궁 아래에 두고 나왔다. 당장이라도 동생이 소화될지 모르는 상황이기에, 라이오스는 결단을 내린다. "식량은 던전 안에서 자급자족하자!" 그것은 다시 말해, 슬라임, 바질리스크, 미믹 심지어 드래곤까지도 먹겠다는 뜻이다! 가라, 모험자여, 그대의 앞을 가로막는 것은 다 먹어 치우며 던전을 돌파해라!',42,2,1,'#FF9800','star','https://image.tmdb.org/t/p/original/xC5GyeIzLsSRizJE5LedGShNgBa.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:47:35');
INSERT INTO catalog_groups VALUES(223,'사카모토 데이즈','한때 최강의 킬러라 불렸던 사카모토 타로. 사랑에 빠져 은퇴하지만 과거가 그의 발목을 잡기 시작한다. 이제, 사카모토는 사랑하는 가족을 지키기 위해 싸워야만 하는데.',42,2,1,'#FF9800','star','https://image.tmdb.org/t/p/original/blSthAPRbEOJBowdxppeQqNPRh9.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:47:45');
INSERT INTO catalog_groups VALUES(224,'피지컬: 아시아','8개국을 대표하는 피지컬 최강자들이 국가의 명예를 걸고 대결한다. 극한의 체력과 인내심의 한계를 건 치열한 전투 끝에 단 하나의 국기만이 남게 된다.',44,2,1,'#DC2626','star','https://image.tmdb.org/t/p/original/823qOjKt0V0N9S6h2uoqu1IA15f.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:47:54');
INSERT INTO catalog_groups VALUES(225,'레이디 두아','가짜일지라도 명품이 되고 싶었던 여자 사라킴. 어디서나 그녀의 이름을 들을 수 있지만 어디서도 진짜 그녀를 만날 수는 없다. 예리한 시선과 끈질긴 집념의 형사 무경이 그 미스터리한 정체를 추적한다.',45,2,1,'#9333EA','music','https://image.tmdb.org/t/p/original/4YWpfFrtd6PBAQmkI44DEkCP13O.jpg',1,'published',0,0,'2026-02-28 08:45:15','2026-03-02 08:48:10');
INSERT INTO catalog_groups VALUES(226,'프랑켄슈타인','과학자 빅터 프랑켄슈타인과 그의 손에서 탄생한 괴물이 펼치는 이야기. 고전이 된 메리 셸리의 소설을 오스카 수상 감독 기예르모 델토로가 영화화했다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/hpXBJxLD2SEf8l2CspmSeiHrBKX.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:31:32');
INSERT INTO catalog_groups VALUES(227,'언포기버블','살인죄로 복역 후 출소한 루스. 과거를 용서해주지 않는 냉담한 사회에서 고통받던 그녀는 오래전 헤어져야 했던 동생을 찾으러 나선다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/kbOB9DGl8qwhDRcXOmXfmcmadeD.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:31:40');
INSERT INTO catalog_groups VALUES(228,'리브 더 월드 비하인드','호화로운 임대 주택으로 휴가를 떠난 가족. 그런데 사이버 공격으로 기기가 고장 나고, 두 명의 낯선 사람이 불쑥 찾아오면서 불길한 일이 전개되기 시작한다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/5cRw2QHQz5bp7W2KLdSpZoFoTTw.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:31:49');
INSERT INTO catalog_groups VALUES(229,'아이리시맨','2000년, 양로원에서 쓸쓸하게 늙어가는 프랭크 시런은 1975년 빌 버팔리노의 딸 결혼식 참석을 위해 길을 떠났던 날을 회상한다. 영화는 제2차 세계대전에 참전했던 노동자 출신의 프랭크가 어떻게 청부살인업자로 활약하게 됐는지 따라가며 주변 인물과 관계를 조명한다. 지미 호파는 전미운수노조의 수장으로서 막강한 권력을 누리고, 프랭크 시런을 범죄로 끌어들인 러셀 버팔리노는 살해 건수를 배당하는 설계자다. 법무장관으로 지명된 로버트 케네디의 견제, 그로 인한 지미의 감옥행은 나비효과처럼 예기치 못한 결과로 이어지는데...',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/1RDto0tLo8Fhq7OcwgDaM7nECb7.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:31:58');
INSERT INTO catalog_groups VALUES(230,'돈 룩 업','지구를 향해 돌진하는 혜성의 존재를 발견한 두 천문학자. 임박한 재앙을 전 인류에 경고하려 언론사를 찾아다니기 시작한다. 하지만 다른 데 정신이 팔린 세상은 시큰둥한 반응뿐. 그래서요?',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/xMJvffWIaW9MtlY9aIXKViUNeIO.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:32:10');
INSERT INTO catalog_groups VALUES(231,'익스트랙션 2','고도로 숙련된 전직 특수 요원 타일러 레이크. 죽음의 문턱에서 가까스로 살아 돌아온 그가 또다시 위험천만한 작전에 뛰어든다. 임무는 하나. 무자비한 갱스터의 가족을 감옥에서 탈출시켜라.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/wRxLAw4l17LqiFcPLkobriPTZAw.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:32:19');
INSERT INTO catalog_groups VALUES(232,'해벅','마약 절도 사건이 통제 불능으로 치닫는 상황. 지칠 대로 지친 경찰이 정치가의 아들을 구하기 위해 부패한 도시의 지하 범죄 세계와 싸우며 길을 헤쳐 나간다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/7rKyFSg6SdLoCRCVoWLjL5k658k.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:32:35');
INSERT INTO catalog_groups VALUES(233,'백 인 액션','평범한 가정을 꾸리기 위해 CIA를 떠났던 두 엘리트 첩보 요원 맷과 에밀리. 그런데 15년 만에 신분이 들통나면서 다시 스파이의 세계로 뛰어들게 된다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/mkxGpqh4yOYqtENv01IrDcesFRf.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:32:46');
INSERT INTO catalog_groups VALUES(234,'더 립','허름한 은닉처에서 수백만 달러의 현금을 발견한 마이애미 경찰. 신뢰에 금이 가기 시작하면서 모든 사람, 모든 것이 의심의 대상이 된다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/3F2EXWF1thX0BdrVaKvnm6mAhqh.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:33:01');
INSERT INTO catalog_groups VALUES(235,'더 킬러','결정적 순간에 아슬아슬하게 타깃을 놓친 암살자. 사적인 감정은 없다면서도, 이 응징을 위해 국제적인 추격전에 뛰어든다. 그 여정에서 의뢰인들, 그리고 그 자신과의 싸움이 시작된다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/mRmRE4RknbL7qKALWQDz64hWKPa.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:33:13');
INSERT INTO catalog_groups VALUES(236,'더 킹: 헨리 5세','잉글랜드 왕의 후계자가 될 생각은 조금도 없는 방탕한 왕자, 할. 그는 왕궁을 등진 채 민중들과 어울려 지내고 있다. 하지만 아버지가 돌아가신 후 장남인 그는 헨리 5세로 즉위하고, 그동안 그토록 피하고 싶었던 삶을 살 수밖에 없다. 왕궁 내 정치와 혼란, 아버지가 남긴 전쟁을 이끌어가야 하는 젊은 왕. 뿐만 아니라 그는 가장 친한 친구이자 멘토였지만 이제는 늙은 알코올중독자가 되어버린 기사 존 폴스타프를 포함해, 과거의 삶과 관련된 감정들로 괴로워한다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/pmwTANjISHvxOmO3iz5kRGAArso.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:33:25');
INSERT INTO catalog_groups VALUES(237,'아웃사이드 더 와이어','가까운 미래 치열한 접전 지역. 드론 조종사가 원치 않게 이곳에 파견된다. 그의 지휘관은 기밀 속 존재인 사이보그. 둘은 함께 핵 공격을 막는 위험한 임무에 뛰어든다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/lOSdUkGQmbAl5JQ3QoHqBZUbZhC.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:33:36');
INSERT INTO catalog_groups VALUES(238,'Rebel Moon — 파트 1: 불의 아이','우주 변방의 위성에 자리한 평화로운 농촌 마을. 마더월드의 무자비한 세력이 이곳에 위협을 가하기 시작한다. 이제 생존을 위한 한 줄기 희망은 외지에서 온 수수께끼 같은 인물에 달려 있다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/sRLC052ieEzkQs9dEtPMfFxYkej.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:33:48');
INSERT INTO catalog_groups VALUES(239,'하우스 오브 다이너마이트','출처 불명의 단일 미사일이 미국으로 발사됐다. 일촉즉발의 위기에서 요동치는 정세. 과연 누가 책임지고 어떻게 대응할 것인가.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/5SVRVwBfHCIkffiq0MmbdvnHWSz.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:33:57');
INSERT INTO catalog_groups VALUES(240,'그레이 맨','그 누구도 실체를 몰라 그레이 맨으로 불리는 CIA의 암살 전문 요원이우연히 CIA의 어두운 비밀을 발견한다. 이런 그의 목에 현상금을 건 소시오패스 기질의 전직 요원. 세계 곳곳을 배경으로 두 사람의 쫓고 쫓기는 추격전이 펼쳐진다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/27Mj3rFYP3xqFy7lnz17vEd8Ms.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:34:06');
INSERT INTO catalog_groups VALUES(241,'레드 노티스','인터폴이 중범죄 피의자를 대상으로 내리는 전 세계적 경보인 레드 노티스. 세계 곳곳에서 지명 수배범을 추적하고 체포하는 것이 그 목적이다. 어느 날 초유의 도난 사건이 발생하고, 그로 인해 FBI 최고의 프로파일러(드웨인 존슨)가 라이벌 관계의 두 범죄자(갤 가돗, 라이언 레이놀즈)와 만나면서 모든 게 엇나가기 시작한다. 늘 한발 앞서 도망치는 사기꾼을 잡기 위해 그들은 어쩔 수 없이 싫어도 이를 악물고 힘을 합쳐야 한다. 이제 무슨 일이 일어날지 그 누구도 장담할 수 없다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/p34WRcgkN2QIHcds5FtFiSpV3PC.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:34:15');
INSERT INTO catalog_groups VALUES(242,'캐리온','크리스마스이브, 항공기에 위험한 물건을 실으라는 강요를 받은 공항 보안 요원. 이 위협에서 벗어나려면, 의문의 여행자보다 한 수 앞서 움직여야 한다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/rhc8Mtuo3Kh8CndnlmTNMF8o9pU.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:34:24');
INSERT INTO catalog_groups VALUES(243,'루','Netflix 오리지널 | 스릴러 영화',48,2,1,'#E50914','film','https://occ-0-988-993.1.nflxso.net/dnm/api/v6/mAcAr9TxZIVbINe88xb3Teg5_OA/AAAABSiLtDPajg9dlnI83QUIe_XtSUhqWeWO-kaV3kG4z2XgVQRY8vTAxjsOzw27IIoUlijWpR41I0n0sgDDk7Dbntm0hcxTbXbM08WwLSNVn20GSA0DX1ZcBbFGwgTil79lXto-Jg.jpg?r=78b',1,'published',2,1,'2026-02-28 08:54:12','2026-03-02 09:03:03');
INSERT INTO catalog_groups VALUES(244,'6 언더그라운드','죽음을 위장하고 사라진 억만장자. 그가 전 세계에서 최정예 요원들을 선발한다. 존재하지 않았던 것처럼 개인의 모든 기록을 지우고 스스로 ‘고스트’가 된 여섯 명의 정예요원이 펼치는 지상 최대의 작전을 담은 액션 블록버스터. 잔인한 독재자의 피로 세상을 물들여라!',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/eFw5YSorHidsajLTayo1noueIxI.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:36:37');
INSERT INTO catalog_groups VALUES(245,'아틀라스','AI를 극도로 불신하는 탁월한 대테러 분석가. 로봇 반역자를 체포하러 나선 임무가 틀어지면서, AI에 의지할 수밖에 없는 상황을 맞닥뜨린다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/3TNSoa0UHGEzEz5ndXGjJVKo8RJ.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:36:47');
INSERT INTO catalog_groups VALUES(246,'일렉트릭 스테이트','고아가 된 10대 소녀. 오래전 잃어버린 남동생을 찾아 미스터리한 로봇과 함께 길을 떠나는데. 그 여정에서 한 밀수꾼과 그의 재치 있는 조수를 만나 동행이 된다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/2n7lYEeIbucsEQCswRcVB6ZYmMP.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:36:57');
INSERT INTO catalog_groups VALUES(247,'스펜서 컨피덴셜','경찰에서 전과자로 추락한 스펜서. 그가 보스턴 경찰 두 명의 죽음에 얽힌 음모를 파헤친다. 이런 일엔 파트너가 있어야 제맛이지. 겁 없는 싸움꾼 호크가 그와 함께한다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/ftODZXaXpWtV5XFD8gS9n9KwLDr.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:37:07');
INSERT INTO catalog_groups VALUES(248,'아미 오브 더 데드','좀비들이 점령한 라스베이거스, 최후의 도박이 시작된다. 도시의 격리 구역으로 침투하는 용병 무리. 사상 최고의 강도 작전은 어떤 결말을 맞을 것인가.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/c0izdYdnTe4uMRifHgvTA85wPz0.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:37:19');
INSERT INTO catalog_groups VALUES(249,'더 유니온','뉴저지 출신의 건설 노동자. 추억 속에 남아 있던 고교 시절 여친으로 인해 첩보 임무에 투입되면서 평범한 남자에서 예비 스파이로 거듭난다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/4ft6TR9wA6bra0RLL6G7JFDQ5t1.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:37:29');
INSERT INTO catalog_groups VALUES(250,'Rebel Moon — 파트 1: 불의 아이','우주 변방의 위성에 자리한 평화로운 농촌 마을. 마더월드의 무자비한 세력이 이곳에 위협을 가하기 시작한다. 이제 생존을 위한 한 줄기 희망은 외지에서 온 수수께끼 같은 인물에 달려 있다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/sRLC052ieEzkQs9dEtPMfFxYkej.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:37:43');
INSERT INTO catalog_groups VALUES(251,'하트 오브 스톤','베일에 싸인 글로벌 평화유지 조직. 이곳에 속한 첩보원이 시간과의 싸움을 벌인다. 조직이 보유한 가장 가치 있고 위험한 무기를 훔치려는 해커를 막기 위해.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/m1k24MwmoqAdKMPJDaBLwdB5Tps.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:37:59');
INSERT INTO catalog_groups VALUES(252,'트리플 프런티어','마약왕의 돈을 훔치기 위해 다시 뭉친 전직 공수특전단 요원들. 왕년의 실력을 발휘하지만, 예상치 못한 위기가 닥친다. 의리마저 흔들리는 그들, 무사히 해낼 수 있을까.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/s9I2LmQMYCanl6DvC3X1AOHs2r8.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:38:10');
INSERT INTO catalog_groups VALUES(253,'레블 리지','작은 도시를 방문한 전직 해병대원. 사촌의 보석 신청에 쓰려던 현금 가방을 관할 경찰에게 부당하게 압수당하자 그곳에 만연한 부패에 정면으로 맞서기로 한다.',48,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/cyKH7pDFlxIXluqRyNoHHEpxSDX.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:38:25');
INSERT INTO catalog_groups VALUES(254,'시니어 이어','치어리딩 공연 중 사고를 당해 코마에 빠진 소녀. 20년 후 서른일곱 살이 되어 깨어난다. 그럼 이제 고등학생 시절의 꿈을 실행에 옮길 차례. 졸업 파티 퀸이 되고 말 거야!',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/3FJ53wbpjSAGY98KYiHJ4DQccDr.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:38:35');
INSERT INTO catalog_groups VALUES(255,'내 이름은 마더','은둔 생활을 하던 군 출신 암살자. 복수에 혈안이 된 무자비한 범죄자들의 손아귀에서 한 번도 만난 적 없는 딸을 지키기 위해 세상 밖으로 나온다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/n5NSF8wZeWQHHZtuWgbRAVpqXFR.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:38:43');
INSERT INTO catalog_groups VALUES(256,'와호장룡: 운명의 검','뛰어난 무공으로 한때 이름을 떨치고 무림계에서 물러나 쉬던 여무사 유수련. 전설의 청명보검을 악랄한 하데스 다이로부터 지키기 위해 그녀가 돌아온다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/rT54o3GyVFvk5EQMXSLoSTnUo6V.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:38:51');
INSERT INTO catalog_groups VALUES(257,'마리아','음악이 인생의 전부였고 무대가 존재의 이유였던 세기의 프리마돈나, 불멸의 소프라노, 마리아 칼라스가 오로지 자신만을 위해 준비한 마지막 무대.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/9iw4a6AQkxUO3EuRn59Vgrqf0zO.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:39:03');
INSERT INTO catalog_groups VALUES(258,'우먼 인 캐빈 10','취재를 위해 초호화 크루즈에 승선한 기자가 한 승객이 바다로 추락하는 모습을 목격한다. 하지만 아무도 자신의 말을 믿어주지 않자, 그녀는 위험을 무릅쓰고 진실을 밝혀내려 한다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/9IHZeCusOd7RUaQpUrQJlKqjsUZ.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:39:13');
INSERT INTO catalog_groups VALUES(259,'선과 악의 학교','절친 소피와 아가사는 어느 날 신비한 존재에 의해 마법 학교로 휩쓸려 간다. 이 학교는 미래의 동화 속 영웅과 악당을 키워내는 곳. 운명을 알 길 없는 이곳에서 두 친구의 우정은 계속될 수 있을까.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/tSxbUnrnWlR5dQvUgqMI7sACmFD.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:39:25');
INSERT INTO catalog_groups VALUES(260,'댐즐','매력적인 왕자와 결혼하게 된 젊은 여성. 그런데 신부가 아니라 불을 내뿜는 용에게 바칠 제물이 되면서, 꿈꿔왔던 결혼이 순식간에 치열한 생존 싸움으로 변한다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/deLWkOLZmBNkm8p16igfapQyqeq.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:40:02');
INSERT INTO catalog_groups VALUES(261,'버드 박스','미지의 재앙이 인류를 휩쓴다. 세상이 뒤집힌 지 5년. 용케 살아남은 여자와 그녀의 아이들이 또다시 위기에 처한다. 안전한 곳을 향해, 그들은 필사적인 모험을 감행한다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/pDKFL1zcHzEpmz4MJA5JJnRbJeD.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:40:11');
INSERT INTO catalog_groups VALUES(262,'카우보이의 노래','코엔 형제의 독창적인 세계에서 탄생한 개척 시대 이야기가 펼쳐진다. 미국의 서부 개척 시대를 배경으로 펼쳐지는 연작 서부극. 한 편 한 편, 서로 다른 개성으로 빚은 여섯 편의 이야기 속에서, 코언 형제의 진가가 빛을 발한다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/12RXkIWUXwOHXgAmlxJNIWRGrri.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:40:20');
INSERT INTO catalog_groups VALUES(263,'애덤 프로젝트','시간 여행 중 2022년에 불시착한 전투기 파일럿 애덤 리드. 그가 12살 시절의 자기 자신과 한 팀이 되어 미래를 구하는 임무에 나선다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/ewUqXnwiRLhgmGhuksOdLgh49Ch.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:40:33');
INSERT INTO catalog_groups VALUES(264,'퍼플 하트','파병이 예정된 해병대원과 위장 결혼을 한 뮤지션 지망생. 가짜였던 둘의 관계는 비극으로 인해 어느새 진심이 되어버린다.',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/jdZM1Gs6DtRGvosgqaXRrIkvYX7.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:40:44');
INSERT INTO catalog_groups VALUES(265,'러브 앤 몬스터스','괴물이 가득한 세상에서 살아가는 사람들의 이야기',49,2,1,'#E50914','film','https://image.tmdb.org/t/p/original/lA5fOBqTOQBQ1s9lEYYPmNXoYLi.jpg',1,'published',0,1,'2026-02-28 08:54:12','2026-03-02 08:40:52');
INSERT INTO catalog_groups VALUES(266,'블랙의 신부','결혼을 통해 최상류층에 진입하겠다는 야망을 품은 사람들. 이들이 상류층 재혼 전문 결혼정보회사의 도움으로 최고 등급과 결혼하기 위한 여정에 나선다.',39,2,1,'#1C1917','tv','https://image.tmdb.org/t/p/original/cTIfK6Vdp4B1fljaRFjMWrzavC.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:25:26');
INSERT INTO catalog_groups VALUES(267,'트렁크','어느 날 갑자기 호숫가에 트렁크가 떠오른다. 그로 인해 드러나기 시작하는 비밀스러운 결혼 서비스, 그 서비스로 만난 두 남녀의 이상한 결혼. 그들에겐 어떤 비밀이 숨어있을까.',39,2,1,'#374151','tv','https://image.tmdb.org/t/p/original/79DCyZhUcFsiGfyjNlFH1lS1t4c.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:25:35');
INSERT INTO catalog_groups VALUES(268,'애나 만들기','대담한 사업가인가, 아니면 사기꾼인가? 독일 출신 상속녀 신분으로 접근해서 뉴욕 엘리트층의 마음을 사로잡은 애나 델비. 한 기자가 애나의 숨겨진 실체를 파헤치기 시작한다.',39,2,1,'#7C3AED','tv','https://image.tmdb.org/t/p/original/fiKQKFsjahOr8qj7QsUUHO9E70t.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:25:45');
INSERT INTO catalog_groups VALUES(269,'하이라키','상위 0.01%의 소수가 법이자 질서로 군림하는 주신고등학교. 그곳에 비밀을 품은 전학생이 나타나면서 견고했던 그들만의 세계에 균열이 생긴다. 청춘의 사랑과 우정, 복수와 연민이 뒤엉킨 이야기.',39,2,1,'#0F172A','tv','https://image.tmdb.org/t/p/original/bG6eCywmJT81OjhBG4qj9M2ErnY.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:25:58');
INSERT INTO catalog_groups VALUES(270,'살인자ㅇ난감','우발적인 첫 살인 후 연이어 사람을 죽이게 된 평범한 청년. 자신을 끈질기게 추적하는 형사와 끝없이 쫓고 쫓기는 게임을 시작한다.',39,2,1,'#1E3A5F','tv','https://image.tmdb.org/t/p/original/viQZtznvR20oTTSbXp6MPAWkGB2.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:26:12');
INSERT INTO catalog_groups VALUES(271,'소년심판','소년범을 혐오하는 까칠한 판사가 지방법원 소년부에 부임한다. 복잡다단한 사건들을 다루며, 소년범에 대한 반감, 정의와 형벌에 대한 굳건한 신념 사이에서 균형을 잡아간다. 청소년 범죄율이 가장 높은 법원이라니 이제 법정의 칼바람은 예고된 것일까.',39,2,1,'#1C1917','tv','https://image.tmdb.org/t/p/original/eW6CqrGSRUk6xMbdCjreMQiP5W8.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:26:21');
INSERT INTO catalog_groups VALUES(272,'킹덤','2019년 1월 Netflix에서 방영을 시작한 좀비물. 병든 왕을 둘러싸고 흉흉한 소문이 떠돈다. 왕에게 이상한 일이 벌어지고 있다는 걸 알게 된 왕세자 이창이 왕을 진료한 의원을 찾아 나선다. 어둠에 뒤덮인 조선, 기이한 역병에 신음하는 산하. 동래 지휼현에 왔다가 역병의 실체를 보게 되고, 호위무사인 무영과 함께 이 병이 전국적으로 퍼져나가는 걸 막기 위해 싸운다. 정체 모를 악에 맞서 백성을 구원할 희망은 오직 세자뿐인데...',39,2,1,'#78350F','tv','https://image.tmdb.org/t/p/original/jRhJlV4inm8wAAqTeHUX5HpjZcc.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:26:34');
INSERT INTO catalog_groups VALUES(273,'마이 네임','아빠를 잃었다. 그것도 바로 눈앞에서. 남은 딸은 결심한다. 반드시 내 손으로 복수하겠노라고. 목표를 위해서라면 방법은 상관없다. 마약 조직의 언더커버가 되어 경찰에 잠입하는 것이라 해도.',39,2,1,'#1E293B','tv','https://image.tmdb.org/t/p/original/x0eIZv8bJYjfTu7VkTOxHU8B91c.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:26:55');
INSERT INTO catalog_groups VALUES(274,'그렇게 사건 현장이 되어 버렸다','백악관 관저에서 발생한 살인 사건. 국빈 만찬에 참석한 직원과 귀빈 모두가 용의선상에 오른 가운데, 천재적인 괴짜 탐정이 사건 해결에 나선다.',39,2,1,'#374151','tv','https://image.tmdb.org/t/p/original/rhwN3mIN89zlDveR0gv0VkrspXa.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:27:30');
INSERT INTO catalog_groups VALUES(275,'지옥','어느 날 기이한 존재로부터 지옥행을 선고받은 사람들. 지옥으로부터의 고지를 받은 자는 어김 없이 예정된 시간에 지옥의 사자들에게 끌려가는 일이 서울 한복판에서 모두가 지켜보는 가운데 일어난다. 충격과 두려움에 휩싸인 도시에 대혼란의 시대가 도래한 가운데, 신흥 종교 단체 새진리회의 의장 정진수는 이것이 진정으로 현실 세계에서 일어나고 있는 신의 집행임을 사람들에게 설파한다. 한편 일부는 새진리회에 맞서 싸우며 사건의 실체를 밝히려 한다.',39,2,1,'#0F172A','tv','https://image.tmdb.org/t/p/original/ikN8ABD9pXHuW4JFqTEHr3ae8rd.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:28:02');
INSERT INTO catalog_groups VALUES(276,'로맨틱 어나니머스','누구와도 눈을 마주칠 수 없는 천재 쇼콜라티에와 누군가와 닿는 것조차 싫은 제과 회사 후계자. 그런데 어째서인지, 두 사람이 서로에게만은 거부 반응이 일어나지 않는다.',39,2,1,'#BE185D','tv','https://image.tmdb.org/t/p/original/2h4rN6HWyvZLyGsfNNzJyQFsfG5.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:28:13');
INSERT INTO catalog_groups VALUES(277,'부트캠프','학창 시절 괴롭힘을 당했던 십 대가 충동적으로 미 해병대에 입대한다. 그곳에서 다양한 배경의 동료 신병들과 함께하며 새로운 삶의 목표와 뜻밖의 형제애를 발견한다.',39,2,1,'#1E3A5F','tv','https://image.tmdb.org/t/p/original/7a78G7fisRp9N9upjyX5b3GNRNI.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:28:22');
INSERT INTO catalog_groups VALUES(278,'멜로무비','영화에만 빠져 살던 그가 까칠한 영화감독 지망생에게 빠져버린다. 설렘 가득했던 시작과 꿈처럼 스친 만남, 그리고 갑작스러운 이별의 순간. 시간이 흘러 우연히 만난 둘에게 새로운 사랑은 피어날까.',39,2,1,'#F472B6','tv','https://image.tmdb.org/t/p/original/9QjIFAVFN7Pe4MbF2O7oHvLkFsI.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:28:31');
INSERT INTO catalog_groups VALUES(279,'스파이가 된 남자','정보 수집에 일가견이 있는 퇴직 교수. 사립 탐정의 제안으로 사건 해결을 위한 잠입 스파이로 나서면서 인생에 새로운 활력을 찾는다.',39,2,1,'#1E293B','tv','https://image.tmdb.org/t/p/original/6EObfIe4akZGvCLXwXLJw3kPitQ.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:28:44');
INSERT INTO catalog_groups VALUES(280,'대환장 기안장','주인장 기안84가 기획하고 운영하는 기상천외한 민박이 울릉도에 문을 연다! 민박 직원 방탄소년단 진과 배우 지예은이 함께하는 힐링과 킬링의 예측 불가한 공간, 청춘 투숙객들이 기안적 낭만에 빠져든다.',39,2,1,'#D97706','tv','https://image.tmdb.org/t/p/original/cHBRJc2ON9WfL71fuvnsWDHRCFN.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:28:56');
INSERT INTO catalog_groups VALUES(281,'도적: 칼의 소리','무법천지의 땅 간도에 모여든 거친 도적들. 소중한 조국과 사랑하는 사람을 지키기 위해 물불을 가리지 않고 싸운다. 설령 목숨을 거는 한이 있더라도.',39,2,1,'#92400E','tv','https://image.tmdb.org/t/p/original/swdlL4gCeRsYU5pC2wh9fzzQt2V.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:29:04');
INSERT INTO catalog_groups VALUES(282,'삼체','여러 시대에 걸쳐 온 지구를 뒤흔들 사실을 발견한 각 대륙의 저명 과학자 다섯 명. 이제 과학의 법칙들이 밝혀지고 실존적 위협이 드리우기 시작한다.',40,2,1,'#1E3A5F','tv','https://image.tmdb.org/t/p/original/ciizJ9Okzt9tBBGK7Q3T14LFT2j.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:29:12');
INSERT INTO catalog_groups VALUES(283,'테스터먼트: 모세 이야기','왕자이자 선지자였던 모세의 놀라운 삶을 조명하는 다큐드라마 시리즈. 신학자와 역사가들의 통찰이 더해져 이해를 돕는다.',40,2,1,'#92400E','tv','https://image.tmdb.org/t/p/original/tKoO0zhN4ukIdCTWY1QNmYNsIHN.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:29:22');
INSERT INTO catalog_groups VALUES(284,'보디가드','《보디가드》는 밀실 속 정치 권력을 다루는 영국 드라마 시리즈다. 주인공 데이비드 버드(리처드 매든)는 영웅의 면모를 지녔지만, 불안정한 성격의 파병 군인. 전역 후 런던 경찰청 소속 특수경호대(RaSP)에 배치된 그는 야망이 넘치고, 강직한 성품의 내무장관 줄리아 몬터규(킬리 호스)의 경호를 맡는다. 정치인을 믿지 않는 그가 정치인의 안전을 책임져야 하는 상황. 임무와 신념 사이에서 갈등하는 데이비드는 결국 무엇을 선택할 것인가.',40,2,1,'#1C1917','tv','https://image.tmdb.org/t/p/original/tvYf5SOIgAumuVoYn2eYKlotAbf.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:29:33');
INSERT INTO catalog_groups VALUES(285,'아바타: 아앙의 전설','아바타로 밝혀진 소년이 전쟁에 휩싸인 세계를 구하려 한다. 그러기 위해서는 네 가지 원소의 힘을 마스터하고, 자신을 막으려 혈안이 된 무자비한 적에 맞서 싸워야 한다.',40,2,1,'#0369A1','tv','https://image.tmdb.org/t/p/original/imlTCObfzISogbvcwB1dokoXAIc.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:29:57');
INSERT INTO catalog_groups VALUES(286,'퀸스 갬빗','1950년대 한 보육원, 체스에 천재적인 재능을 보이는 소녀. 점점 더 넓은 세계로 향하며, 체스 스타의 여정을 이어간다. 하지만 더 이기고 싶다면 중독부터 극복해야 한다.',40,2,1,'#7C3AED','tv','https://image.tmdb.org/t/p/original/5N5dSOrysuquExvn8Gpp5jMEf6u.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:30:18');
INSERT INTO catalog_groups VALUES(287,'언테임드','광활한 요세미티 국립공원. 이곳에서 한 여성이 사망하면서 연방 수사 요원이 무법지대로 발을 들인다. 자연이 자신의 법칙 외에는 그 무엇에도 복종하지 않는 곳으로.',40,2,1,'#1E293B','tv','https://image.tmdb.org/t/p/original/oGsh97JAA6LYu92B6TEswrjac8W.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:30:30');
INSERT INTO catalog_groups VALUES(288,'코타로는 1인 가구',replace('딩동! 낯선 꼬마가 우리 집 초인종을 눌렀다.\n\n“바로 옆 203호로 이사 온 사토라고 한다. 인사차 방문하였다”라고 말하며 선물로 고급 티슈 상자를 건네는 꼬마. 아이의 이름은 사토 코타로, 원룸 건물 시미즈에 혼자 살게 된 네 살 독거 소년이다.\n\n코타로는 장난감 칼을 옆에 차고 매일 혼자 장을 보러 나선다.\n\n천진난만하면서도 어른스러운 코타로. 이 아이의 의젓한 모습을 보며 주변 이웃들도 조금씩 변화해가기 시작한다.\n\n부모님과 함께 살 수 있는 그 날까지, 꿋꿋이 혼자 지내기로 마음먹은 네 살 꼬마의 이야기.\n\n허름한 원룸 건물에 혼자 이사 온 꼬마 아이. 자기 힘으로 모든 걸 해내는 어린 소년과 옆집의 빈털터리 만화가 청년이 친구가 된다.\n\n츠무라 마미의 코미디 만화를 바탕으로 한 애니메이션은 ''가장 따뜻한 일본 만화''로 불리는 원작은 140만 부 이상 판매된 인기 작품이다.','\n',char(10)),26,2,1,'#F59E0B','tv','https://image.tmdb.org/t/p/original/wZ7GS3eVx0I3EcpN8KNmM5vlHgS.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:30:38');
INSERT INTO catalog_groups VALUES(289,'프리즘 윤무곡','1900년대 초 런던, 명문 미술학교에 입학한 젊은 일본인 여성이 같은 학교에 다니는 천재 화가 청년과 만난다. 처음에는 경쟁심에 불타던 두 사람. 하지만 생각지도 못한 사랑이 싹트기 시작한다.',26,2,1,'#BAE6FD','tv','https://image.tmdb.org/t/p/original/MYrRkkE2L0DKw5CRjbCYeQjLAq.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:30:47');
INSERT INTO catalog_groups VALUES(290,'이게 바로 카켄 스타일','어머니의 장례식을 치르기 위해 고향에 돌아온 래퍼 토니. 자신에게 십 대 아들이 있다는 사실을 알게 되면서, 아버지로서의 삶과 오랜 꿈 사이에서 흔들리기 시작한다.',26,2,1,'#D97706','tv','https://image.tmdb.org/t/p/original/rTTEaQ54i6zUSDGnVyuNbvu86wf.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:30:56');
INSERT INTO catalog_groups VALUES(291,'이세계 삼촌','17년 동안 혼수상태에 빠져 이제는 중년이 된, 타카후미의 삼촌이 어느 날 눈을 뜬다. 알아들을 수 없는 말을 하고 마법의 힘을 휘두르며.',27,2,1,'#7C3AED','star','https://image.tmdb.org/t/p/original/piMRImsn3ZQerFmPdAoXgmOpc7R.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:31:05');
INSERT INTO catalog_groups VALUES(292,'그의 이야기 & 그녀의 이야기','한 사람은 형사, 다른 한 사람은 뉴스 기자. 서로에게 등을 돌린 부부가 살인 사건의 진실을 두고 맞붙는다. 서로를 유력한 용의자로 의심하면서.',27,2,1,'#F472B6','star','https://image.tmdb.org/t/p/original/n4hJLZmBG8kZccNn7bNgBDsVQ6a.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:31:14');
INSERT INTO catalog_groups VALUES(293,'조용한 희망','내 이름은 알렉스. 아이 아빠의 정신적 학대를 피해 딸을 데리고 도망쳤다. 이제 나는 여자이자 엄마로서 세상에 정착해 홀로 육아를 하고 미래를 준비해야 한다. 궂은일을 해서라도 반드시.',27,2,1,'#BAE6FD','star','https://image.tmdb.org/t/p/original/eX0tVkoLokMQGne4lBHqUgJUE6o.jpg',1,'published',0,1,'2026-02-28 09:02:24','2026-03-02 08:31:23');
INSERT INTO catalog_groups VALUES(294,'폴라','최고의 청부 살인자 덩컨. 은퇴를 준비하던 그는 막대한 퇴직금을 눈앞에 두고 음모에 말려든다. 잔혹한 킬러 군단과의 대결, 마지막 살인 게임의 방아쇠가 당겨졌다.',47,2,1,'#1C1917','film','https://image.tmdb.org/t/p/original/lSCKo6QGJ88Gn3espNnvL87CinA.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:19:23');
INSERT INTO catalog_groups VALUES(295,'무도실무관','힘든 사람을 그냥 지나치지 못하는 무술 유단자 이정도. 보호관찰관 김선민이 그런 정도를 알아보고 ‘무도실무관’을 권한다. 이제 전자발찌 대상자를 감시하며 범죄를 예방하는 그들의 활약이 펼쳐진다.',47,2,1,'#1E3A5F','film','https://image.tmdb.org/t/p/original/wSZbtiFIK1fkKZdSRtn2kz2Ttfd.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:19:48');
INSERT INTO catalog_groups VALUES(296,'더 포가튼 배틀','세 젊은이가 2차 세계 대전의 포화 속으로 들어간다. 연합군의 글라이더 조종사, 네덜란드 출신의 독일군 그리고 레지스탕스로. 방법은 달랐지만, 이들이 원한 건 오직 자유, 그 하나였다.',47,2,1,'#374151','film','https://image.tmdb.org/t/p/original/qmCCXB6fn1Sjztm4t56Xviw0uDI.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:20:05');
INSERT INTO catalog_groups VALUES(297,'크로스','어느 날 결혼생활에 극한의 미션이 떨어진다면? 아내에게 과거를 숨긴 채 베테랑 주부로 살아가는 전직 요원. 뜻하지 않게 위험한 임무에 얽히게 되는데, 어느새 형사인 아내까지 함께 휘말리고 만다.',47,2,1,'#0F172A','film','https://image.tmdb.org/t/p/original/eq24kKsd5S1NCZDrQ2fBkKDkWle.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:20:34');
INSERT INTO catalog_groups VALUES(298,'인터셉터','훔친 핵미사일 16기로 미국을 공격하려는 테러리스트들. 한 장교가 이들을 상대로 외딴 미사일 요격 기지에서 목숨을 건 전투를 벌인다.',47,2,1,'#1E293B','film','https://image.tmdb.org/t/p/original/i2tcQ9nDJpdJELPA82eCd7Irasd.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:20:56');
INSERT INTO catalog_groups VALUES(299,'신칸센 대폭파','시속 100km 이하로 속도가 떨어지면 폭탄이 터지는 도쿄행 초고속 열차. 당국은 촌각을 다투며 탑승자 모두를 구하려 한다.',47,2,1,'#7C3AED','film','https://image.tmdb.org/t/p/original/zHP9pMtYuMZBluNZNBP9i5fX2US.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:21:14');
INSERT INTO catalog_groups VALUES(300,'마이 네임 이즈 벤데타','과거의 적들이 아내와 아내의 오빠를 살해하자, 딸과 함께 밀라노로 도망친 전직 마피아 집행자. 그곳에서 몸을 숨긴 채 복수를 계획한다.',47,2,1,'#374151','film','https://image.tmdb.org/t/p/original/3WwqXEdDtA81iMJcEVYmxqVD3bD.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:21:25');
INSERT INTO catalog_groups VALUES(301,'데몬 시티: 악귀 죽이기','가족을 살해했다는 누명을 쓴 채 식물인간으로 방치되었던 전직 킬러. 도시를 점령한 가면 쓴 ‘악귀들’을 향한 그의 거침없는 복수가 시작된다.',47,2,1,'#0F172A','film','https://image.tmdb.org/t/p/original/hD2SN5bbqxk0kcRmsATJkXObgnZ.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:21:36');
INSERT INTO catalog_groups VALUES(302,'독전 2','아직 추적은 끝나지 않았다. 집념에 불타는 형사가 아시아 최대 마약 조직의 진실과 그 실체를 찾기 위해 수사를 이어간다.',47,2,1,'#1C1917','film','https://image.tmdb.org/t/p/original/kW75Wz92dGMcs8rcEUScDMUwvna.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:21:49');
INSERT INTO catalog_groups VALUES(303,'황야','세상은 폐허로 변했다. 오직 힘이 지배하는 무법천지가 되었다. 그 황량한 땅에서 살아가는 자들이 생존을 위해 최후의 사투를 벌이는 액션 블록버스터.',47,2,1,'#92400E','film','https://image.tmdb.org/t/p/original/qLQiQXe8tHk8mokDH0LoKudPDH3.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:22:20');
INSERT INTO catalog_groups VALUES(304,'카터','기억을 잃은 채 깨어난 남자. 귀에 장착된 장치를 통해 의문의 목소리가 들려오고, 이제 이 목소리의 지시에 따라 위험천만한 인질 구조 작전에 뛰어들어야 한다.',47,2,1,'#1E3A5F','film','https://image.tmdb.org/t/p/original/nHWr40LGgyxymEhZCOA2WHATPpn.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:22:32');
INSERT INTO catalog_groups VALUES(305,'바람의 검심 최종장: 더 비기닝','마침내 십자 흉터의 비밀이 밝혀진다. 혼돈의 시대, 세상에 피의 비를 뿌리던 검객 켄신과 그의 인생을 바꾼 토모에. 켄신의 모든 이야기는 여기에서 시작되고 여기에서 끝난다.',47,2,1,'#78350F','film','https://image.tmdb.org/t/p/original/iGmfHHa3CSqKrH3yeS9CQVLAVUl.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:22:44');
INSERT INTO catalog_groups VALUES(306,'엑스테리토리얼','전직 특수부대 출신 군인 자라. 아들이 미국 영사관에서 흔적도 없이 사라지자, 아들을 찾기 위해 온힘을 쏟아붓고 그 과정에서 어두운 음모를 발견한다.',47,2,1,'#1E293B','film','https://image.tmdb.org/t/p/original/14UFWFJsGeInCbhTiehRLTff4Yx.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:24:08');
INSERT INTO catalog_groups VALUES(307,'모글리: 정글의 전설','동물들의 손에 자란 인간의 아이, 모글리. 거대한 운명을 짊어진 소년이 숙명적인 싸움을 시작한다. 정글과 인간 세계를 오가는 늑대 소년의 성장을 그린 모험 드라마.',48,2,1,'#065F46','film','https://image.tmdb.org/t/p/original/pApaVlxJCp2o4mrzCAD3AaLjq77.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:24:17');
INSERT INTO catalog_groups VALUES(308,'섀도우의 13','살인 훈련을 받은 젊은 킬러가 무자비한 범죄 조직으로부터 한 소년을 구출하려 한다. 소년만 구할 수 있다면 멘토를 등지는 것은 물론, 그 길을 가로막는 누구라도 제거할 것이다.',48,2,1,'#374151','film','https://image.tmdb.org/t/p/original/3R96c2rQp6Jt1xQYX4LYdY6ETdS.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:24:32');
INSERT INTO catalog_groups VALUES(309,'보석 도둑: 더 하이스트 비긴스','기발한 사기꾼 레한이 잔혹한 라이벌 라잔을 따돌리기 위해 치밀한 다이아몬드 강탈 작전을 계획한다. 치열한 두뇌 싸움과 긴장감 넘치는 전개가 돋보이는 작품.',48,2,1,'#D97706','film','https://image.tmdb.org/t/p/original/kFXtAwJYbRTqiyQpE9kDc8qEP3X.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:24:49');
INSERT INTO catalog_groups VALUES(310,'SAS 특수부대: 라이즈 오브 블랙 스완','파리행 열차가 탈취됐다. 적색 수배가 내려진 악명 높은 블랙 스완에 의해. 그 열차에 여자 친구와 함께 타고 있던 특수 부대 대원 톰. 그는 혼자서 싸움을 시작한다. 아주 힘든 싸움을.',48,2,1,'#1C1917','film','https://image.tmdb.org/t/p/original/feLcWM4lSq4fNSRZomeKVDBBOLK.jpg',1,'published',0,1,'2026-02-28 09:07:57','2026-03-02 08:25:14');
INSERT INTO catalog_groups VALUES(311,'사냥개들','사람 목숨보다 돈이 먼저인 사채업의 세계에 휘말린 두 청년이 거대한 악의 세력에 맞서 목숨 걸고 싸우는 이야기를 그린 넷플릭스 시리즈 . 주먹만큼은 자신 있는 건우와 우진이 은퇴한 사채업계의 전설 최 사장과 함께 법 위에 군림하는 악명 높은 불법 사채업자 명길에게 맞서는 이야기.',39,2,1,'#1C1917','tv','https://image.tmdb.org/t/p/original/b2iWqSFpuy9CS5XWiAmnLzNv9eP.jpg',1,'published',8,1,'2026-02-28 09:11:47','2026-03-02 08:14:18');
INSERT INTO catalog_groups VALUES(312,'고백의 역사','사랑에 빠진 10대 소녀, 학교 최고 인기남의 마음을 얻기 위해 곱슬머리를 생머리로 바꾸기로 결심한다.',39,2,1,'#7C3AED','tv','https://image.tmdb.org/t/p/original/oBcvmHD7lbaX8RZ7NXvO05fIJef.jpg',1,'published',4,1,'2026-02-28 09:11:47','2026-03-02 08:48:26');
INSERT INTO catalog_groups VALUES(313,'D.P.','탈영병을 잡는다. 이등병 준호에게 떨어진 새로운 임무. 그는 탈영병들을 추적하며 지독하게 고통스러운 현실을 마주한다. 그리고 아무리 도망쳐도 벗어날 수 없다는 것도 알게 된다.',39,2,1,'#374151','tv','https://image.tmdb.org/t/p/original/yFNGc3OR81NGdJL3yZCBrjDIluf.jpg',1,'published',6,1,'2026-02-28 09:11:47','2026-03-02 08:48:23');
INSERT INTO catalog_groups VALUES(314,'데블스 플랜','인간의 사회적 가면을 벗기겠다는 악마의 제안. 최고의 두뇌 플레이어 자리를 두고 참가자들이 일주일간 대결을 펼친다. 극강의 브레인 서바이벌 예능.',39,2,1,'#0F172A','tv','https://image.tmdb.org/t/p/original/jTpcWY1vjydAMbxQzoTs7WXVDvl.jpg',1,'published',4,1,'2026-02-28 09:11:47','2026-03-02 08:48:38');
INSERT INTO catalog_groups VALUES(315,'스위트홈','인간이 무시무시한 괴물로 변하는 세상. 사방이 공포로 물들었다. 이제 소수의 생존자들은 끝까지 인간성을 놓치지 않기 위해 목숨 건 사투를 벌인다.',39,2,1,'#1E3A5F','tv','https://image.tmdb.org/t/p/original/mceCXNTny6a5F3rQgShLoyARw4l.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:15:51');
INSERT INTO catalog_groups VALUES(316,'경성크리처','어둠이 드리운 비극의 시대 1945년. 경성 최고의 자산가가 죽은 이도 찾아낸다는 토두꾼과 만났다. 생존이 전부였던 두 사람은 이내 인간의 탐욕으로 탄생한 괴물을 마주하게 되는데…',39,2,1,'#78350F','tv','https://image.tmdb.org/t/p/original/peVe0NQNdZMXwtTohnv8iwJQb2d.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:16:03');
INSERT INTO catalog_groups VALUES(317,'이두나!','새로운 삶과 학교생활에 적응하려 애쓰는 대학생 원준. 조금 특이한 사정이 있는데, 바로 화려한 K-pop 아이돌 시절을 뒤로하고 돌연 은퇴한 미모의 하우스 메이트와 산다는 것.',39,2,1,'#BE185D','tv','https://image.tmdb.org/t/p/original/4XpGAQgA2lnCoFJKx31b1fevYtr.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:16:24');
INSERT INTO catalog_groups VALUES(318,'종이의 집','1명의 천재, 8명의 공범, 철저히 준비한 세기의 강도. 스페인 조폐국에서 인질극까지 벌인 이들은 과연 포위 경찰을 따돌리고 거액의 돈과 함께 달아날 수 있을까?',39,2,1,'#DC2626','tv','https://image.tmdb.org/t/p/original/xGexTKCJDkl12dTW4YCBDXWb1AD.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:16:39');
INSERT INTO catalog_groups VALUES(319,'범인은 바로 너!','유재석과 허당 탐정들의 예측불허 추리 예능. 당신이 웃어넘긴 모든 순간이 단서가 된다! 추리는 초짜, 웃음만 고수인 7인의 허당 탐정단이 맞닥뜨리는 10개의 사건, 숨막히는 추적, 뜻밖의 손님들. 예측불허 사건 속, 탐정단은 과연 최후의 배후를 밝혀낼 수 있을 것인가?',39,2,1,'#D97706','tv','https://image.tmdb.org/t/p/original/56YHtJezhk6y7SczrYz6pmmf9oU.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:16:55');
INSERT INTO catalog_groups VALUES(320,'에밀리, 파리에 가다','새로운 열정과 새로운 패션. 그리고 새로운 에밀리? 결단력 있는 미국인 마케터 에밀리가 파리에서 꿈꾸던 일을 하게 되면서 새로운 삶과 사랑을 헤쳐 나간다.',40,2,1,'#F472B6','tv','https://image.tmdb.org/t/p/original/jXTZaHarR9TZiMoQwiQWsGYXqnS.jpg',1,'published',2,1,'2026-02-28 09:11:47','2026-03-02 08:17:25');
INSERT INTO catalog_groups VALUES(321,'죠죠의 기묘한 모험','유서 깊은 죠스타 가문에 얽힌 기묘한 이야기를 아는가. 각기 다른 세상에서 애칭 ''죠죠''를 공유하며 살아가는 주인공들. 시간적 공간적 배경은 달라도, 추구하는 가치는 다르지 않다. 악의 세력을 물리치고 정의가 이기는 세상을 만들라.',27,2,1,'#D97706','star','https://image.tmdb.org/t/p/original/mLKN1dsimKPiXCZ48KED0X8a02t.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:17:36');
INSERT INTO catalog_groups VALUES(322,'사이버펑크: 엣지러너','부패와 사이보그 임플란트로 가득한 디스토피아 세상. 재능은 넘치지만 무모한 길거리 소년이 무법의 용병, 엣지러너가 되기 위해 사투를 벌인다.',27,2,1,'#7C3AED','star','https://image.tmdb.org/t/p/original/9Mo7R35rv14LVYLHdU5Cq7dJuGv.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:17:51');
INSERT INTO catalog_groups VALUES(323,'나의 행복한 결혼','쓸모없는 존재로 여겨지며 가족에게 학대받는 미요. 하지만 막강한 약혼자를 만나 진정한 자신의 모습을 깨닫고, 숨겨져 있던 능력을 서서히 발휘하기 시작한다.',27,2,1,'#F9A8D4','star','https://image.tmdb.org/t/p/original/7uyRCBMQIWwJSWIR2aCrvPjbPzi.jpg',1,'published',2,1,'2026-02-28 09:11:47','2026-03-02 08:48:35');
INSERT INTO catalog_groups VALUES(324,'케이팝 데몬 헌터스','케이팝 슈퍼스타 루미, 미라, 조이. 매진을 기록하는 대형 스타디움 공연이 없을 때면 이들은 또 다른 활동에 나선다. 바로 비밀 능력을 이용해 팬들을 초자연적 위협으로부터 보호하는 것.',27,2,1,'#0F172A','star','https://image.tmdb.org/t/p/original/w3Bi0wygeFQctn6AqFTwhGNXRwL.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:18:25');
INSERT INTO catalog_groups VALUES(325,'낙원의 밤','범죄조직의 에이스 태구는 사랑하는 누나와 조카를 의문의 교통사고로 한순간에 잃는다. 참혹한 비극의 배후에 상대 조직이 있음을 직감한 태구는 모든 것을 걸고 복수를 실행한다. 거사를 마친 태구는 몸을 숨긴 제주도에서 불법 무기상 삼촌과 단둘이 사는, 죽음의 그림자를 간직한 재연을 만나는데...',47,2,1,'#1E293B','film','https://image.tmdb.org/t/p/original/MocpW8Wrp8uireBg6bT6Y6TKWC.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:18:39');
INSERT INTO catalog_groups VALUES(326,'길복순','청부살인이 본업이지만 겉으로 보기에는 평범한 이벤트 회사인 MK 소속 킬러 길복순은 작품은 반드시 완수해 내는 성공률 100%의 킬러이자, 10대 딸을 둔 엄마다. 업계에서는 아무도 범접할 수 없는 에이스지만, 딸 재영과의 관계는 서툴기만 한 싱글맘인 그는 자신과 딸 사이의 벽을 허물기 위해 퇴사까지 결심한다. MK 대표 차민규의 재계약 제안의 답을 미룬 채, 마지막 작품에 들어간 복순은 임무에 숨겨진 진실을 알게 된 후, 회사가 허가한 일은 반드시 시도해야 한다는 규칙을 어기게 된다. 그 소식을 들은 MK는 물론, 모든 킬러들의 타겟이 되고야 마는데…',47,2,1,'#DC2626','film','https://image.tmdb.org/t/p/original/mGwzJbtX6zU0SdtxeHn1sNNK8JW.jpg',1,'published',0,1,'2026-02-28 09:11:47','2026-03-02 08:19:13');
